import React, { useState, useEffect, useRef } from 'react';
import { CheckCircle, Award, Users, TrendingUp, ChevronLeft, ChevronRight } from 'lucide-react';
import './AboutUsPage.css';

const campusData = {
  depok: [
    { src: '/facilities/ruang1.jpeg', title: 'Robotics Lab D', desc: 'Lab robotika kampus Depok' },
    { src: '/facilities/ruang2.jpeg', title: 'Electronics D', desc: 'Lab elektronik lengkap' },
  ],
  kalimalang: [
    { src: '/facilities/ruang3.jpeg', title: 'IoT Lab J', desc: 'Zona IoT Kalimalang' },
    { src: '/facilities/ruang4.jpeg', title: 'AI Lab J', desc: 'AI & ML Lab' },
  ],
  karawaci: [
    { src: '/facilities/ruang5.jpeg', title: 'Multimedia Lab K', desc: 'Studio multimedia' },
    { src: '/facilities/ruang6.jpeg', title: '3D Printing K', desc: 'Rapid prototyping' },
  ],
};

const teamStructure = {
  director: {
    img: '/DSC_0039.JPG',
    name: 'Prof. Dr. Nur Sultan Salahuddin, SKom., MT.',
    role: 'Director of Study Center / Kepala Pusat Studi'
  },
  members: [
    { name: 'Aqilla Rahman Musyaffa', role: 'Research Engineer / Peneliti', img: '/DSC_0067.JPG' },
    { name: 'Nora Trisna Tumewa', role: 'Lab Manager / Manager Administrasi', img: '/DSC_0071.JPG' },
    { name: 'Salahuddin Yusuf Zhafran Fajr', role: 'RnD Lab Technician', img: '/DSC_0067.JPG' },
    { name: 'Faisal Firdaus', role: 'Practice Lab Technician', img: '/DSC_0071.JPG' },
  ]
};

function FacilitySlider({ slides }) {
  const [current, setCurrent] = useState(0);
  const [startX, setStartX] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const autoRef = useRef(null);

  const next = () => setCurrent(prev => (prev + 1) % slides.length);
  const prev = () => setCurrent(prev => (prev - 1 + slides.length) % slides.length);

  useEffect(() => {
    autoRef.current = setInterval(next, 4000);
    return () => clearInterval(autoRef.current);
  }, []);

  const resetAuto = () => {
    clearInterval(autoRef.current);
    autoRef.current = setInterval(next, 4000);
  };

  const handleStart = (x) => {
    setStartX(x);
    setIsDragging(true);
    clearInterval(autoRef.current);
  };

  const handleEnd = (x) => {
    if (!isDragging) return;
    const diff = startX - x;

    if (diff > 50) next();
    else if (diff < -50) prev();

    setIsDragging(false);
    resetAuto();
  };

  return (
    <div
      className="facility-slider"
      onMouseDown={(e) => handleStart(e.clientX)}
      onMouseUp={(e) => handleEnd(e.clientX)}
      onTouchStart={(e) => handleStart(e.touches[0].clientX)}
      onTouchEnd={(e) => handleEnd(e.changedTouches[0].clientX)}
    >
      <div
        className="slider-track"
        style={{ transform: `translateX(-${current * 100}%)` }}
      >
        {slides.map((slide, i) => (
          <div key={i} className="facility-slide">
            <img src={slide.src} alt={slide.title} />
            <div className="facility-slide-overlay">
              <h4>{slide.title}</h4>
              <p>{slide.desc}</p>
            </div>
          </div>
        ))}
      </div>

      <button className="facility-btn prev" onClick={prev}>
        <ChevronLeft size={20} />
      </button>
      <button className="facility-btn next" onClick={next}>
        <ChevronRight size={20} />
      </button>
    </div>
  );
}

export default function AboutUsPage() {
  const [activeCampus, setActiveCampus] = useState('depok');

  return (
    <>
      {/* HEADER */}
      <section className="page-header-we">
        <h1>Tentang Kami</h1>
        <p>Modern Lab with Multi Campus Facilities</p>
      </section>

      <section className="aboutus-section">

        {/* MISSION */}
        <div className="about-content">
          <div className="about-text">
            <h2>Our Mission</h2>
            <p>LabConnect empowers students with hands-on learning.</p>

            <div className="about-features">
              <div><CheckCircle size={18}/> Innovation</div>
              <div><Award size={18}/> Excellence</div>
              <div><Users size={18}/> Community</div>
              <div><TrendingUp size={18}/> Growth</div>
            </div>
          </div>

          <div className="about-image">
            <img src="/5.jpeg" alt="lab" />
          </div>
        </div>

        {/* FACILITIES */}
        <div className="facilities-section">
          <div className="campus-tabs">
            {Object.keys(campusData).map(c => (
              <button
                key={c}
                className={activeCampus === c ? 'active' : ''}
                onClick={() => setActiveCampus(c)}
              >
                {c}
              </button>
            ))}
          </div>

          <FacilitySlider slides={campusData[activeCampus]} />
        </div>

        {/* TEAM */}
        <div className="team-section">
          <h2>Our Team</h2>

          {/* DIRECTOR */}
          <div className="team-director">
            <div className="team-card">
              <img src={teamStructure.director.img} />
              <h3>{teamStructure.director.name}</h3>
              <p>{teamStructure.director.role}</p>
            </div>
          </div>

          {/* MEMBERS */}
          <div className="team-grid">
            {teamStructure.members.map((m, i) => (
              <div key={i} className="team-card">
                <img src={m.img} />
                <h3>{m.name}</h3>
                <p>{m.role}</p>
              </div>
            ))}
          </div>

          {/* STATS */}
          <div className="stats">
            <div>
              <h2>40+</h2>
              <p>Alumni</p>
            </div>
            <div>
              <h2>20+</h2>
              <p>Asisten Aktif</p>
            </div>
          </div>
        </div>

      </section>
    </>
  );
}
